INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('1', 'Morning Wood', 'Pictures of wood, trees, and textures printed or painted or placed on a wood surface (e.g. wallpaper).', NULL, NULL);
