INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('3', 'Paper Trail', 'Pictures and scans of paper surfaces.', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('4', 'Stone Cold', 'Catchall album for pictures of concrete, rock, stone, brick, gravel, and asphalt.', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('5', 'Textile Mill', 'Pictures of textures in or on cloth or fabric.', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('6', 'Erotic Elements', 'Pictures of the four elements: earth, water, fire, and wind (shown through wind movement).', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('7', '100% Organic', 'Food, plants, natural textures in pictures.', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('8', 'Eye of the Beholder', 'Pictures of interesting signage and also public art.', NULL, NULL);
INSERT INTO `snap_albums` (`id`, `album_name`, `album_description`, `cover_image_id`, `featured_post_id`) VALUES ('9', 'Pane in the Glass', 'Pictures of glass surfaces or glass objects.', NULL, NULL);
