INSERT INTO `snap_settings` (`setting_key`, `setting_val`) VALUES ('custom_css_admin', '/* SKIN_START */\n.metadata-selector-row { display: flex; justify-content: space-between; align-items: center; margin-top: -15px; margin-bottom: 50px; }\n        .skin-switcher-form { display: flex; align-items: center; gap: 10px; }\n        .skin-switcher-form label { margin: 0 !important; }\n        .control-group-flex { display: flex; align-items: center; gap: 20px; }\n        .control-group-flex input { flex: 1; }\n        .active-val { width: 50px; text-align: right; font-family: monospace; }\n        .hex-display { font-family: monospace; }\n/* SKIN_END */');
INSERT INTO `snap_settings` (`setting_key`, `setting_val`) VALUES ('custom_css_public', '/* SKIN_START */\nbody { background-image: url(\'skins/true-grit/textures/paintedconcrete.jpg\'); background-size: cover; background-repeat: no-repeat; background-attachment: fixed; }\n:root { --wall-bg: #ffffff; }\n:root { --overlay-opacity: 85; }\n:root { --overlay-color: #f5f5f5; }\n:root { --header-bg: #bababa; }\n:root { --header-opacity: 85; }\n:root { --footer-bg: #bababa; }\n:root { --footer-opacity: 85; }\n.tg-header-inside, .tg-photo-wrap, #system-footer .inside, #browse-grid, #justified-grid { max-width: 1453px; }\n.tg-header-inside, .tg-photo-wrap, #browse-grid { padding-left: 40px; padding-right: 40px; }\n.tg-header-inside { flex-direction: row; }\n#browse-grid { --grid-cols: 4; }\n#justified-grid { --justified-row-height: 280; }\n.square-grid .thumb-link, .cropped-grid .thumb-link { aspect-ratio: auto; overflow: visible; }\n.is-photo-page img.post-image, img.tg-image, .inline-asset, .snap-inline-frame, .static-transmission .description .align-left { border: none !important; box-shadow: 0 8px 40px rgba(0,0,0,0.5), 0 2px 10px rgba(0,0,0,0.3) !important; }\n.square-grid .thumb-link, .cropped-grid .thumb-link, .justified-item { border: none !important; box-shadow: 0 4px 20px rgba(0,0,0,0.4) !important; }\n.site-title-text, .logo-area a { font-family: \"Philosopher\", sans-serif; }\n.static-page-title, .photo-title-footer { font-family: \"Raleway\", sans-serif; }\n.static-content, .description { font-family: \"DM Sans\", sans-serif; }\n#system-footer .inside, #system-footer p, #sig-text { font-family: \"Raleway\", sans-serif; }\n:root { --page-bg: #ffffff; }\n:root { --accent: #1c1c1c; }\n:root { --accent-hover: #000000; }\n#system-footer p, #sig-text, #system-footer .sep, #system-footer a { color: #303030; }\n#system-footer a:hover { color: #cccccc; }\n.site-title-text { font-size: 25px; }\n.site-title-text { text-transform: lowercase; }\n.site-title-text { letter-spacing: 3px; }\n.site-title-text { font-weight: 300; }\n.nav-menu a, .site-title-text, .logo-area a { color: #292929; }\n.nav-menu a:hover, .nav-menu a.active, .logo-area a:hover { color: #ffffff; }\n#system-footer p, #sig-text { font-size: 11px; }\n#tg-photobox { padding-bottom: 0px; }\n#tg-header { height: 65px; }\n#infobox { height: 50px; }\n#system-footer { padding-top: 20px; padding-bottom: 20px; }\n.static-content { margin-top: 10px; }\n.blogroll-grid { grid-template-columns: 1fr; }\n.blogroll-canvas { max-width: 900px; }\n.blogroll-grid { gap: 60px; }\n.blogroll-peer-desc { display: block; }\n.blogroll-peer-url { display: block; }\n/* ENGINE: smack-lightbox */\n/* SKIN_END */\n\n');
