INSERT INTO `snap_pages` (`id`, `slug`, `title`, `content`, `image_asset`, `image_size`, `image_align`, `image_shadow`, `is_active`, `menu_order`, `created_at`) VALUES ('1', 'about', 'About The Photographer', '<p>[img:1|full|center]I (Sean McCormick) am a lifelong Albertan who prefers towns to cities, cats to dogs, books to sports, and tea to coffee. My obsession began at age five when my grandmother gave me a No. 2 Brownie. It was a tactical error on her part; the resulting film and processing costs nearly drove her into bankruptcy over the next two years.</p>\n<p>[years_since year=\"1973\" month=\"11\" day=\"04\"] years later, I still own that Brownie, along with a large collection of antique film cameras and 35mm SLRs. These days, you can usually find me wandering the walking trails in Strathmore, Alberta, with at least one camera in handâ€”much to the chagrin of the local waterfowl, who wish I would just bugger off.</p>\n<p>I am a graduate of the New York Institute of Photography and have worked as a wedding and portrait photographer in the past. I\'ve since returned to my roots as a dedicated hobbyist. As such, I politely decline all requests to photograph events, groups, or individuals. The professional work occasionally seen in my portfolio remains there strictly for sentimental reasons.</p>\n<p>Only a very small sampling of my photography is available through this site. To explore the rest of my work, visit my <a href=\"https://linktr.ee/mccormickphotography\">Linktree</a>.</p>', '', '', '', '0', '1', '1', '2026-03-15 17:16:22');
INSERT INTO `snap_pages` (`id`, `slug`, `title`, `content`, `image_asset`, `image_size`, `image_align`, `image_shadow`, `is_active`, `menu_order`, `created_at`) VALUES ('2', 'image-use', 'Image Use', '<p><h3>Ownership and Certification</h3><br />\nAll images on foundtextures.ca are original photographic works created and owned by Sean McCormick, Strathmore, Alberta, Canada. Each image file carries this license embedded in its XMP copyright metadata. Sean McCormick certifies that he is the original creator of all images distributed under this license and has the right to grant the permissions described herein.</p>\n<p><h3>What You May Do</h3></p>\n<ul>\n  <li>Use the textures in personal projects â€” art, photography, design, print, digital, whatever you\'re making.</li>\n  <li>Use the textures in commercial projects â€” client work, products for sale, advertising, publications.</li>\n  <li>Modify, scale, composite, layer, filter, or otherwise alter the textures to suit your work.</li>\n  <li>Use the textures in unlimited projects. This license does not expire and is not project-limited.</li>\n  <li>Distribute work that incorporates the textures as part of a larger creative work.</li>\n  <li>Use in AI training datasets, model development, and machine learning projects.</li>\n</ul>\n<p><h3>What You May Not Do</h3></p>\n<ul>\n  <li>Resell the texture files themselves as standalone texture files, in packs, on stock sites, or as part of any product where the textures are the primary thing being sold.</li>\n  <li>Distribute the original files as downloads or as part of a collection.</li>\n  <li>Claim original authorship of the unmodified texture images.</li>\n  <li>Remove or alter the XMP copyright metadata embedded in the original files.</li>\n</ul>\n<p><h3>Attribution</h3><br />\nAttribution is not required. If you want to credit the source, \"Texture from foundtextures.ca\" is sufficient and appreciated. No specific format is required.</p>\n<p><h3>Resulting Work</h3><br />\nThe original copyright for a texture file belongs to Sean McCormick. Once you incorporate a texture into your own work, the copyright of the resulting piece is yours. You can sell it, give it away, or publish it without restriction. What you cannot do is redistribute or sell the original texture files themselves, unmodified, as the primary product. They are intended to be blended into your artwork. Hoarding textures now for use later is also acceptable and even encouraged.</p>\n<p><h3>AI Training</h3><br />\nThese textures are explicitly permitted for use in AI training datasets. Take a penny, leave a penny. (Before you freak out, I do not use AI to create my images. I did use it to help create the software running the site you\'re using right now. If you take, you give back. That\'s what this is.)</p>\n<p><h3>No Warranty</h3><br />\nThese textures are provided as-is. Sean McCormick makes no warranties about fitness for any particular purpose. Use them. Make things. Better yet, make ART. That\'s what they\'re for.</p>', '', '', '', '0', '1', '2', '2026-03-15 17:20:47');
INSERT INTO `snap_pages` (`id`, `slug`, `title`, `content`, `image_asset`, `image_size`, `image_align`, `image_shadow`, `is_active`, `menu_order`, `created_at`) VALUES ('3', 'home', 'UNLIMITED TEXTURES, ALMOST UNLIMITED USE', '<p>These are the surfaces the world forgets about. Rust working through paint. Concrete absorbing decades. Wood giving itself back to weather. Handmade textures on rainy days. Vintage paperwork discovered at the dump. Captured, scanned, weirdly catalogued, and handed to you free.</p>\n<p>[post_count] textures in the catalogue. More coming. All available for download from the Google Drive repository in full resolution. Just hit the download link at bottom right of the image you want and Bob\'s yer uncle.</p>\n<p>Free for personal and commercial use. No attribution required. No account needed. Every texture photographed, not generated. Every surface real. Download and build something. [<a href=\"https://foundtextures.ca/page.php?slug=image-use\" target=\"_blank\" rel=\"noopener nofollow\">Full license and permitted uses</a> â†’]</p>\n<p>If these textures have saved you time or made something better, the Ko-fi link is there. No obligation, no subscription, no guilt. Take a penny, leave a penny.</p>\n<p>My YouTube channel is coming â€” a different take on pixel hunting. The process behind the photography, the compositing, the catalogue. Subscribe. You\'ll know when it drops.</p>\n<p>[spacer:10]<br />\n[embed:mailerlite]</p>', 'media_assets/1775195143_69cf5407db253.jpg', 'full', 'center', '0', '1', '0', '2026-04-03 01:48:22');
